321 |     <script>
322 |         const SUPABASE_URL = 'https://xvldfsmxskhemkslsbym.supabase.co';
323 |         const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU';
324 |         const sb = supabase.createClient(SUPABASE_URL, SUPABASE_KEY);
