336 |         function switchTab(tab) {
337 |             document.querySelectorAll('.section').forEach(el => el.classList.remove('active'));
338 |             document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
339 |             document.getElementById('view-' + tab).classList.add('active');
