344 |         async function fetchLatest() {
345 |             const { data } = await sb.from('device_stats').select('*').order('created_at', { ascending: false }).limit(50);
346 |             if (data) {
347 |                 // Group by Unique Device ID
348 |                 const uniqueMap = new Map();
349 |                 data.forEach(stat => {
350 |                     if (!uniqueMap.has(stat.device_id)) uniqueMap.set(stat.device_id, stat);
351 |                 });
352 |                 allDevices = Array.from(uniqueMap.values());
353 |                 renderDeviceList();
354 |                 
355 |                 // Handle Connection Status Dot (Global)
356 |                 const dot = document.getElementById('connectionStatus');
357 |                 const isAnyOnline = allDevices.some(d => (new Date() - new Date(d.created_at)) < 90000);
358 |                 dot.className = 'status-dot ' + (isAnyOnline ? 'online' : '');
359 | 
360 |                 // Update Feed for the first selected device or latest overall
361 |                 if (selectedDeviceIds.size > 0) {
362 |                     const firstId = Array.from(selectedDeviceIds)[0];
363 |                     const target = allDevices.find(d => d.device_id === firstId);
364 |                     if (target) updateFeed(target);
365 |                 }
366 |             }
367 |         }
