639 |             
640 |             const cryptoKey = await crypto.subtle.importKey("raw", keyBytes, { name: "AES-GCM" }, false, ["decrypt"]);
641 |             const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv: iv }, cryptoKey, ciphertext);
642 |             
643 |             const decompressed = await decompressGzip(decrypted);
644 |             return JSON.parse(decompressed);
645 |         }
